className\":\"relative h-[160px]\",\"children\":[[\"$\",\"div\",\"0\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 0s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Bryl was the most talented software engineer I've mentored in a long time. He's a fast learner, and he always makes sure to deliver quality output given a period of time. He is also very keen on learning new technologies, and I find him to be objectively passionate about tech. He's definitely someone you want on your team.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Cris Lawrence Adrian Militante\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"ICT Director at GCM\"}]]}]]}],[\"$\",\"div\",\"1\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 8s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Intelligent software engineer. Bryl takes lead during software development and can handle and manage teams well.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Ken Gorro\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Senior Developer at Fullscale\"}]]}]]}],[\"$\",\"div\",\"2\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 16s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Was an intern at PocketDevs and sir Bryl was our main trainer to the different technologies we use in the company such as Laravel, Bootstrap, etc. With his guidance, I was equipped with some of the current trends and insights in the tech industry which enabled me to be part of my current company.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Patrick Vince Velasco\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Software Engineer, YNS\"}]]}]]}],[\"$\",\"div\",\"3\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 24s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Sir Bryl's teaching approach is incredibly hands-on, and the projects significantly accelerated my learning process in web development. I am truly grateful for the mentorship I received from him during my web development internship.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"John Edmerson Pizarra\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Jr. Full-stack Developer, PocketDevs\"}]]}]]}],[\"$\",\"div\",\"4\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 32s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Bryl is a good student and software developer who shows professionalism and dedication in whatever he does. His software projects during his academic years are up to standard and is being used by the university for some of its operations. Bryl also demonstrated social awareness and leadership skills through his involvement as an officer/member in various student and special interest groups in the university.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Glenn Pepito\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Professor at University of San Carlos\"}]]}]]}],[\"$\",\"div\",\"5\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 40s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"Bryl and I worked together in various projects where I saw his tenacity to deliver what he promised to do. He is able to meet deadlines without sacrificing the quality of the output, and at times even exceeding the set goals. His dedication to pursue his craft and his mindset as a lifelong learner allow him to be easily mentored, as he is eager to learn new technologies. His enthusiasm at new opportunities makes him a great asset because he does everything with renewed energy and finds ways to optimize existing processes. Bryl sure is a great addition to any team!\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Van Honoridez\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Application Development Analyst at Accenture\"}]]}]]}],[\"$\",\"div\",\"6\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 48s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"The exposure to real projects and guidance from Sir Bryl was instrumental in my growth as a web developer. His approach to teaching and mentoring helped me to understand the intricacies of web development, and I'm now working at Quickway Holdings Inc., applying the skills I learned.\",\"”\"]}],[\"$\",\"div\",null,{\"className\":\"mt-3 pt-3 border-t border-border\",\"children\":[[\"$\",\"p\",null,{\"className\":\"text-xs font-semibold font-geist-sans\",\"children\":\"Zinia Ma. Consuelo R. Trinidad\"}],[\"$\",\"p\",null,{\"className\":\"text-xs text-foreground/50 font-geist-sans\",\"children\":\"Web Developer, Quickway Holdings Inc.\"}]]}]]}],[\"$\",\"div\",\"7\",{\"className\":\"absolute inset-0 transition-all duration-1000\",\"style\":{\"opacity\":0,\"visibility\":\"hidden\",\"animation\":\"fade-slide-show 64s linear infinite 56s\",\"animationFillMode\":\"forwards\"},\"children\":[[\"$\",\"p\",null,{\"className\":\"text-[13px] leading-relaxed text-foreground/80 font-serif line-clamp-4\",\"children\":[\"“\",\"I was just a K-12 undergrad with zero coding experience, but with the guidance of Sir Bryl, I was able to learn and grow exponentially. His mentorship helped me to develop a strong foundation in programming, and I'm now a full-stack developer working freelance projects.\